package service

import (
	"context"
	"errors"

	"go.uber.org/zap"

	"github.com/rede/world-cup-quiniela/internal/domain"
	"github.com/rede/world-cup-quiniela/internal/repository"
	"github.com/rede/world-cup-quiniela/pkg/apperrors"
)

// WebhookPaymentService processes confirmed payment notifications from
// external payment providers and credits the user's balance.
//
// Recurrente carries the user ID in its payload metadata; the service trusts
// the signature-verified value directly.
//
// PayPal uses an opaque payment intent token (custom_id) generated by the
// server before the PayPal order is created. The service resolves the token
// to the associated user and amount, preventing a user from substituting
// another user's ID. Idempotency is enforced by the unique constraint on
// payment_intents.capture_id: a given PayPal capture can credit at most one
// intent, and a given intent can only be captured once.
type WebhookPaymentService interface {
	// CreditFromRecurrente credits amountCents to userID's balance following a
	// confirmed Recurrente transaction. reference is the provider's transaction
	// ID, stored in the audit log for traceability.
	CreditFromRecurrente(ctx context.Context, userID, amountCents int, currency, reference string) error
	// ResolveAndCreditPayPalIntent resolves intentToken to a pending, non-expired
	// payment intent, atomically captures it, and credits the user's balance.
	// Returns nil for idempotent duplicate webhook deliveries (same captureID).
	// Returns apperrors.NotFound when the token is unknown or expired.
	// Returns apperrors.Conflict when the intent is captured by a different captureID.
	ResolveAndCreditPayPalIntent(ctx context.Context, intentToken, captureID string) error
}

type webhookPaymentService struct {
	ledgerRepo repository.BalanceLedgerRepository
	intentRepo repository.PaymentIntentRepository
	audit      AuditLogger
	log        *zap.Logger
}

// NewWebhookPaymentService constructs a WebhookPaymentService.
func NewWebhookPaymentService(
	ledgerRepo repository.BalanceLedgerRepository,
	intentRepo repository.PaymentIntentRepository,
	audit AuditLogger,
	log *zap.Logger,
) WebhookPaymentService {
	return &webhookPaymentService{
		ledgerRepo: ledgerRepo,
		intentRepo: intentRepo,
		audit:      audit,
		log:        log,
	}
}

func (s *webhookPaymentService) CreditFromRecurrente(ctx context.Context, userID, amountCents int, currency, reference string) error {
	return s.creditDirect(ctx, userID, amountCents, currency, reference,
		domain.LedgerKindWebhookRecurrente, domain.AuditActionWebhookPaymentCredit)
}

func (s *webhookPaymentService) creditDirect(ctx context.Context, userID, amountCents int, currency, reference string, kind domain.BalanceLedgerKind, action string) error {
	if amountCents <= 0 {
		return apperrors.Validation("amount_cents must be positive")
	}
	if reference == "" {
		return apperrors.Validation("reference is required for webhook payments")
	}

	credited, err := s.ledgerRepo.CreditIdempotent(ctx, userID, amountCents, kind, reference)
	if err != nil {
		return err
	}
	if !credited {
		s.log.Debug("webhook payment: idempotent re-delivery ignored",
			zap.String("reference", reference),
			zap.String("kind", string(kind)),
		)
		return nil
	}

	resType := "user"
	s.audit.Log(ctx, nil, nil, action, &resType, &userID, map[string]any{
		"amount_cents": amountCents,
		"currency":     currency,
		"reference":    reference,
		"kind":         string(kind),
	})
	return nil
}

func (s *webhookPaymentService) ResolveAndCreditPayPalIntent(ctx context.Context, intentToken, captureID string) error {
	if intentToken == "" {
		return apperrors.Validation("intent token is required")
	}
	if captureID == "" {
		return apperrors.Validation("capture ID is required")
	}

	intent, err := s.intentRepo.CaptureAndCredit(ctx, intentToken, captureID)
	if errors.Is(err, repository.ErrPaymentIntentAlreadyCaptured) {
		s.log.Debug("paypal webhook: idempotent re-delivery ignored",
			zap.String("intent_token", intentToken),
			zap.String("capture_id", captureID),
		)
		return nil
	}
	if err != nil {
		return err
	}

	resType := "payment_intent"
	intentID := int(intent.ID)
	s.audit.Log(ctx, nil, nil, domain.AuditActionWebhookPaymentCredit, &resType, &intentID, map[string]any{
		"user_id":      intent.UserID,
		"amount_cents": intent.AmountCents,
		"currency":     intent.Currency,
		"capture_id":   captureID,
		"kind":         string(domain.LedgerKindWebhookPayPal),
	})
	return nil
}

var _ WebhookPaymentService = (*webhookPaymentService)(nil)
